import React from "react";

export const WhyChoose = (props) => {
  const d = props.data;
  return (
    <div id="why" className="text-center 55lab-why">
      <div className="container">
        <div className="section-title">
          <h2>{d ? d.title : "…"}</h2>
          {d && d.subtitle ? <p>{d.subtitle}</p> : null}
        </div>
        <div className="row">
          {d && d.items
            ? d.items.map((text, i) => (
                <div key={i} className="col-md-6">
                  <div className="55lab-why-item">
                    <i className="fa fa-check" aria-hidden="true"></i>
                    <p>{text}</p>
                  </div>
                </div>
              ))
            : null}
        </div>
      </div>
    </div>
  );
};
